var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"깊게 베이진 않았어요. 다행히 급소는 잘 피했네요.","JPN":"深く斬られたわけではないですね。幸い、急所は外れてます。","ENG":"The wound is not deep. Fortunately, it missed your vital points.","TWN":"下手不重，幸好沒有傷到要害。"},"stage":{"bg":"CLAN_001","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SCHOOL_PRESIDENT_IN_TRAILER_1"},{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"소독을 할 테니 따끔해도 참아요.","JPN":"消毒しますので、痛くても我慢してください。","ENG":"Stay still. The disinfectant is going to sting.","TWN":"我現在要替你消毒，會有點刺痛，你忍耐一下。"},"stage":{"bg":"CLAN_001","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SCHOOL_PRESIDENT_IN_TRAILER_2"},{"id":"L6_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLAN_001","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아까부터 빤히 쳐다보고 있는데, 뭔가 하고 싶은 말이라도 있나요?","JPN":"さっきからずっと私を見つめていますけど、何か話したいことでもありますか？","ENG":"You have been staring at me this whole time. Is there something you wish to say to me?","TWN":"你從剛才就一直盯著我，是有什麼話想說嗎？"},"stage":{"bg":"CLAN_001","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SCHOOL_PRESIDENT_IN_TRAILER_3"},{"id":"L8_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그대와 겨뤄보고 싶소.","JPN":"貴殿と戦ってみたいです。","ENG":"I want to challenge you to a duel.","TWN":"在下想向你下戰帖。"},"stage":{"bg":"CLAN_001","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SCHOOL_C_STAFF_IN_TRAILER_1"},{"id":"L9_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"수업시간 외에 싸움을 거는 건 아카데미 교칙 위반입니다.","JPN":"授業時間外で喧嘩を売ることはアカデミーの校則違反です。","ENG":"Fighting outside of class is against the rules of the Academy.","TWN":"上課時間外的對決是違反校規的。"},"stage":{"bg":"CLAN_001","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SCHOOL_PRESIDENT_IN_TRAILER_4"},{"id":"L10_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"앞으로도 주의해주세요.","JPN":"これからも気をつけてください。","ENG":"Please be mindful of that from now on.","TWN":"再請留意。"},"stage":{"bg":"CLAN_001","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"음… 명심하리다.","JPN":"む……肝に銘じておきます。","ENG":"Mm... I shall keep that in mind.","TWN":"嗯…在下會記住。"},"stage":{"bg":"CLAN_001","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SCHOOL_C_STAFF_IN_TRAILER_2"},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"왜 갑자기 저와 싸우고 싶어하는 거죠?","JPN":"急にどうして私と戦いたいと思ったのですか？","ENG":"Why do you suddenly want to fight me?","TWN":"為什麼突然想和我決鬥呢？"},"stage":{"bg":"CLAN_001","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SCHOOL_PRESIDENT_IN_TRAILER_5"},{"id":"L14_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그건… 잘 모르겠구려.","JPN":"それは……よくわかりません。","ENG":"That... I am not sure.","TWN":"在下…也不知道。"},"stage":{"bg":"CLAN_001","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SCHOOL_C_STAFF_IN_TRAILER_3"},{"id":"L15_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"아마 그대에게서 달콤하고 좋은 향이 나기 때문인 것 같소.","JPN":"おそらく、貴殿から甘くて良い香りがするからかと。","ENG":"Perhaps it is because there is a sweet, pleasant smell coming from you.","TWN":"可能是因為你身上有一種甜甜的香味。"},"stage":{"bg":"CLAN_001","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SCHOOL_C_STAFF_IN_TRAILER_4"},{"id":"L16_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"맥락이 없는 칭찬은 상대를 당혹스럽게 만들 뿐입니다.","JPN":"なんの脈絡もない褒め言葉は、相手を困惑させるだけです。","ENG":"Compliments without context only cause confusion.","TWN":"沒來由的稱讚只會令對方感到困惑。"},"stage":{"bg":"CLAN_001","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SCHOOL_PRESIDENT_IN_TRAILER_6"},{"id":"L17_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"불쾌했다면 미안하오.","JPN":"不快にさせたら申し訳ありません。","ENG":"I apologize if I made you feel uncomfortable.","TWN":"讓你感到不愉快的話，在下道歉。"},"stage":{"bg":"CLAN_001","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SCHOOL_C_STAFF_IN_TRAILER_5"},{"id":"L18_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"시엘 양은 방금 죽을 뻔한 것치곤 제법 침착하군요.","JPN":"シエルさんは、さっき死にそうになったのに結構落ち着いていますね。","ENG":"You seem quite calm for someone who almost died.","TWN":"希爾同學剛才面對生死一瞬間的反應很沉著呢。"},"stage":{"bg":"CLAN_001","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SCHOOL_PRESIDENT_IN_TRAILER_7"},{"id":"L19_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"불필요한 소란은 피우고 싶지 않을 뿐이오.","JPN":"不要な騒ぎは起こしたくないだけです。","ENG":"I do not wish to cause unnecessary disturbances.","TWN":"在下只是不想造成不必要的麻煩。"},"stage":{"bg":"CLAN_001","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SCHOOL_C_STAFF_IN_TRAILER_6"},{"id":"L21_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"시엘 양이 탄환을 막지 않았다면, 사선으로 끼어든 나이엘 양이 당했겠죠.","JPN":"シエルさんが弾丸を防いでいなかったら、射線に割り込んだナイエルさんがやられていたでしょう。","ENG":"If you had not blocked that bullet, it would have hit Naielle, who was charging at you.","TWN":"要不是你擋下子彈，子彈就會打到奈爾。"},"stage":{"bg":"CLAN_001","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SCHOOL_PRESIDENT_IN_TRAILER_8"},{"id":"L22_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그 순간을 포착한 그대도 제법 눈썰미가 있구려.","JPN":"その瞬間を捉えた貴殿も相当な慧眼の持ち主ですね。","ENG":"You have a keen eye, spotting that in the spur of the moment.","TWN":"有發現這件事的你觀察力也很敏銳。"},"stage":{"bg":"CLAN_001","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SCHOOL_C_STAFF_IN_TRAILER_7"},{"id":"L24_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"혹시, 총을 쏜 범인을 찾으려고 하는 거라면 부디 멈춰주시오.","JPN":"もし自分を撃った犯人を探しだすつもりなら、どうか留まっていただけませんか。","ENG":"If you are looking to find whoever shot me, I urge you to cease.","TWN":"不過若你想找出開槍的犯人，希望你可以打消主意。"},"stage":{"bg":"CLAN_001","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SCHOOL_C_STAFF_IN_TRAILER_8"},{"id":"L25_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"어째서죠?","JPN":"どうしてですか？","ENG":"Why do you say that?","TWN":"為什麼呢？"},"stage":{"bg":"CLAN_001","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SCHOOL_PRESIDENT_IN_TRAILER_9"},{"id":"L26_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"본인의 짐작이 맞다면, 그 자가 벌이는 일에는 본인의 책임도 없지 않소.","JPN":"心当たりが合っているとしたら、あの者の仕業には自分にも責任があります。","ENG":"If my assumption is correct, then I am also responsible for his actions.","TWN":"若在下猜得沒錯，會發生這件事在下也有責任。"},"stage":{"bg":"CLAN_001","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SCHOOL_C_STAFF_IN_TRAILER_9"},{"id":"L27_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그러니 범인의 처분은 본인에게 맡겨 줬으면 한다오.","JPN":"ですので、犯人の処分は自分に任せてほしいのです。","ENG":"Therefore, I ask that you leave this matter to me, and I shall deal with him.","TWN":"因此處置犯人一事，希望可以交由在下處理。"},"stage":{"bg":"CLAN_001","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SCHOOL_C_STAFF_IN_TRAILER_10"},{"id":"L28_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLAN_001","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이디스, 미안하지만 저격 사건의 범인을 잡는 건 나중으로 미루도록 하죠.","JPN":"イーディス、申し訳ないのですが、狙撃事件の犯人を捕まえるのは後にしましょう。","ENG":"Edith, I am sorry, but we must delay catching the shooter.","TWN":"伊蒂絲，抱歉，之後再追查狙擊事件的犯人吧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"오케이~ 단서는 찾았지만 학생회장이 그렇게 말한다면 난 낮잠이나 자야…","JPN":"オッケー。手がかりは見つかったけど、生徒会長がそう言うのなら私は昼寝でも……","ENG":"Okay. I found some clues, but if you say so, I'll just go take a nap...","TWN":"OK～雖然我已經有掌握到線索，不過既然學生會長這麼說，那我就去睡午…"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"쿠울…","JPN":"ぐうぅぅ……","ENG":"Zzz...","TWN":"呼嚕…"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"청을 들어주어 고맙구려.","JPN":"頼みを聞きいれてくださりありがとうございます。","ENG":"Thank you for taking heed.","TWN":"謝謝你願意答應在下的請求。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…학생회는 아카데미 학생에게 해를 끼치려 하는 자가 있다면 좌시하지 않습니다.","JPN":"……生徒会はアカデミーの生徒に危害を加える者がいるとするなら、それを座視しません。","ENG":"...The Student Council does not take any incident lightly regarding attempts that may harm students at the Academy.","TWN":"…要是有人想傷害學院的學生，學生會是不會坐視不管的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"하지만 학생의 의사를 존중하는 것 또한 학생회의 역할이겠죠.","JPN":"ですが、生徒の意思を尊重することもまた生徒会の役割でしょう。","ENG":"However, it is also the Student Council's duty to respect the decisions of students.","TWN":"不過學生會也很尊重學生的意見。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"삼 일 유예를 드리겠습니다. 그 뒤부터는 제가 직접 관여하겠어요.","JPN":"3日の猶予を与えます。その後は私が直接関与しますので。","ENG":"I shall give you three days. After that, I will have to intervene.","TWN":"我給你三天的時間，三天後就由我親自接手。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그 정도면 충분하오.","JPN":"それで十分です。","ENG":"That will be enough.","TWN":"三天已足矣。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그나저나…","JPN":"それより……","ENG":"Ah, on another note...","TWN":"不過…"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L49_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"힉-!","JPN":"ひっ！？","ENG":"Heek!","TWN":"嚇-！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"문 밖에서 누가 엿듣고 있나 했더니… 낭자였구려.","JPN":"扉の外で誰が盗み聞きをしているのかと思いましたが……貴殿でしたか。","ENG":"I was wondering who was eavesdropping on us... It was you, blonde maiden.","TWN":"在下還在想是誰在門外偷聽…原來是姑娘你。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"나이엘?","JPN":"ナイエル？","ENG":"Naielle?","TWN":"奈爾？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"누, 누가 엿들었다고 그래? 난 그냥 다친 게 걱정돼서…!","JPN":"ぬ、盗み聞きなんてしてないよ！　私はただ怪我が心配で……！","ENG":"I-I wasn't eavesdropping! I was just worried about your injury...!","TWN":"你，你說誰偷聽！我是擔心你的傷口…！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"걱정…? 아니, 아니지.","JPN":"心配……？　いや、違う。","ENG":"Worried...? No, wait.","TWN":"擔心…？不對，我才沒有擔心。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"이 몸의 진심공격을 견디지 못해서 죽어가고 있는 건 아닌지 확인만 하러 와본 것뿐이라고!","JPN":"この私の本気攻撃に耐えられなくて、死にかけてるんじゃないかって確認しに来てみただけだよ！","ENG":"I was here to check whether you were dying or not after enduring my full-on attack!","TWN":"我只是來確認一下，你是不是被我打到快沒命而已！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"요는 본인이 무사한지 걱정했다는 뜻이구려.","JPN":"要は、自分が無事であるか心配したという意味ですか。","ENG":"In summary, you were worried about my well-being.","TWN":"原來這就是擔心在下身體的意思。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"아니라니까!","JPN":"違うってば！","ENG":"No, I didn't say that!","TWN":"才不是咧！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L9_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"걱정할 것 없소. 보다시피 팔을 조금 다쳤을 뿐이라오.","JPN":"心配ご無用。見てのとおり、腕を少し怪我しているだけです。","ENG":"You need not worry. As you can see, it was merely a graze on my arm.","TWN":"不用擔心，你看，在下只有手臂受一點傷而已。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"흥, 괜찮은 척하긴. 실은 분하고 아파 죽겠으면서.","JPN":"ふん、平気なふりして。本当は悔しくてめっちゃ痛いくせに。","ENG":"Hmph. I know you're just pretending to be okay. In truth, you're angry and in extreme pain, aren't you?","TWN":"哼，裝什麼堅強，明明就很痛吧！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"이해해. 바깥에선 나보다 강한 카운터를 쉽게 만나기 힘들었을 테니 말이야.","JPN":"そりゃそうよね、学校の外では私より強いカウンターに滅多には会えなかったはずだからね。","ENG":"I get it. It's not easy to come around a Counter as strong as I am on the streets.","TWN":"我懂，畢竟在外面很難遇到比我還厲害的制裁者吧。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L14_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"부정하진 않겠소. 본인의 고향에서도 그대를 넘어서는 강자는 흔치 않을 거요.","JPN":"否定はしません。自分の故郷にも貴殿を越える強者は数少ないはずです。","ENG":"I agree. Even in my hometown, it is rare to find someone as strong as you.","TWN":"確實是，在在下的老家也很難見到超越你的高手。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"훗, 당연한 소릴 뭐 그리 길게 해?","JPN":"ふっ、何当たり前なこと言ってんのよ。","ENG":"Heh, well duh. Isn't that obvious?","TWN":"呵，還用你說嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그리고 내 이름은 나이엘이야! 이 몸에게 졌으면 이름 정도는 제대로 알아두라고!","JPN":"それに、私の名前はナイエルだよ！　この私に負けたんだから、名前くらいはちゃんと覚えておきなさいね！","ENG":"By the way, my name's Naielle! Since you lost to me, you should at least remember my name!","TWN":"還有，我的名字是奈爾！既然你成為我的手下敗將，至少要記得是誰打敗你的！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"기억해두리다, 낭자.","JPN":"わかりましたよ、貴殿。","ENG":"I shall remember it, blonde maiden.","TWN":"我會記住的，姑娘。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"너 일부러 그러는 거지!","JPN":"あんた、わざと言ってるんでしょ！","ENG":"You're doing that on purpose, aren't you?!","TWN":"你是故意的吧！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L20_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>큰일났어요, 학생회장님!</color>","JPN":"<color=#ffd34c>大変です、生徒会長！</color>","ENG":"<color=#ffd34c>There's something that requires your attention, Ms. President!</color>","TWN":"<color=#ffd34c>學生會長，不好了！</color>"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"무슨 일이죠? 미카?","JPN":"どうしましたか？　ミカ。","ENG":"What is it, Mika?","TWN":"米卡？發生什麼事？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"이디스 선배의 순찰드론이 외부구역에서 우리 학교 학생들을 찾았어요!","JPN":"イーディス先輩の巡回ドローンが、外部区域でアカデミーの生徒を発見しました！","ENG":"Edith's recon drone found a couple of our students outside of school grounds!","TWN":"伊蒂絲前輩的巡邏無人機在校外找到我們的學生了！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"두 사람이 어떤 패거리와 시비가 붙은 것 같은데…! 이대로라면 누가 크게 다칠지도 몰라요!","JPN":"二人の生徒がある連中とケンカしてるみたいですけど……！　このままだと、誰かが大怪我をするかもしれません！","ENG":"The two seem to be in an argument with another gang...! At this rate, someone's gonna get hurt!","TWN":"他們二個和一群小混混發生爭執…！再這樣下去恐怕會有人受傷！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"우선은 경찰에 신고해주세요.","JPN":"まずは警察に通報してください。","ENG":"Alert the authorities first.","TWN":"先報警吧。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"학생들끼리 문제를 해결하려 하면 오히려 일을 그르치게 될 수도 있으니까요.","JPN":"私たちだけで問題を解決しようとすると、むしろ悪化させることになるかもしれません。","ENG":"If students try to resolve it on their own, it could make the situation worse.","TWN":"要是插手學生之間的問題，我怕情況反而會弄得更糟。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"음…? 그러고보니 나이엘이 어디로 사라졌죠?","JPN":"うん……？　そういえば、ナイエルはどこに消えたのですか？","ENG":"Mm...? Where did Naielle go?","TWN":"嗯…？不過怎麼沒看到奈爾？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"통신을 듣자마자 검을 쥐고 달려갔소.","JPN":"通信を聞くなり、剣を持って走っていきました。","ENG":"She grabbed her sword and ran out as soon as she heard the conversation.","TWN":"她一聽到電話後便奪劍而出。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"아무래도 충돌은 피하기 어렵겠구려.","JPN":"どうやら、衝突を避けることは免れなさそうですね。","ENG":"It seems conflict is inevitable.","TWN":"看來衝突是無法避免的。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};